struct node {
	node () {
		v = "T";
	}
	string v;
	vector<node*> childs;
};

node* convert (vector< vector<int> > const& in, int i, int j, int size) {
	if (size == 0 || i >= in.size() || j >= in.size()) return NULL;
	if (size == 1) {
		node * n = new node();
		n->v = to_string(in[i][j]);
		return n;
	}

	int newS = size/2;

	node * n = new node();

	n->childs.push_back(convert ( in, i, j, size/2) );
	n->childs.push_back(convert ( in, i+newS, j, size/2) );
	n->childs.push_back(convert ( in, i, j+newS, size/2) );
	n->childs.push_back(convert ( in, i+newS, j+newS, size/2) );

	return n;
}

node * convert (vector< vector<int> > const& in) {
	if (in.empty() || in[0].empty() || in.size() != in[0].size() || ((in.size() & (in.size()-1)) != 0)) return NULL;
	return convert ( in, 0,0,in.size());
}

