public class ScratchPad {

    static class Node {
        String value;
        Node[] children;

        Node(String value) {
            this.value = value;
        }

        Node() {
            this.children = new Node[4];
        }
    }

    public static void main(String[] args) {
        int[][] matrix = {
                {1, 2, 3, 4},
                {5, 6, 7, 8},
                {9, 0, 5, 5},
                {9, 1, 5, 5}
        };

        Node root = buildQuadTree(matrix, 0, 0, matrix.length);
        printQuadTree(root);
    }

    private static Node buildQuadTree(int[][] matrix, int row, int col, int size) {
        if (size == 1) {
            return new Node(String.valueOf(matrix[row][col]));
        }

        int newSize = size / 2;
        Node[] children = new Node[4];
        children[0] = buildQuadTree(matrix, row, col, newSize); // Top-left
        children[1] = buildQuadTree(matrix, row, col + newSize, newSize); // Top-right
        children[2] = buildQuadTree(matrix, row + newSize, col, newSize); // Bottom-left
        children[3] = buildQuadTree(matrix, row + newSize, col + newSize, newSize); // Bottom-right

        if (isLeaf(children)) {
            return new Node(children[0].value);
        }

        Node node = new Node();
        node.children = children;
        return node;
    }

    private static boolean isLeaf(Node[] children) {
        String val = children[0].value;
        for (Node child : children) {
            if (child.children != null || !child.value.equals(val)) {
                return false;
            }
        }
        return true;
    }

    private static void printQuadTree(Node node) {
        if (node == null) {
            return;
        }

        // If the node is a leaf, simply print its value
        if (node.children == null) {
            System.out.print(node.value);
            return;
        }

        // Collect and print values for each quadrant
        System.out.print("TL: " + collectValues(node.children[0]) + " ");
        System.out.print("TR: " + collectValues(node.children[1]) + " ");
        System.out.print("BL: " + collectValues(node.children[2]) + " ");
        System.out.print("BR: " + collectValues(node.children[3]) + " ");
    }

    private static String collectValues(Node node) {
        if (node == null) {
            return "";
        }

        // If the node is a leaf, return its value
        if (node.children == null) {
            return node.value;
        }

        // Otherwise, concatenate values from all children
        return collectValues(node.children[0]) +
                collectValues(node.children[1]) +
                collectValues(node.children[2]) +
                collectValues(node.children[3]);
    }

}

